import { Box, Stack, Typography } from '@mui/material';
import ShieldIcon from '@mui/icons-material/Shield';

export interface SecurityHeaderProps {
    title: string;
    subtitle: string;
    icon?: React.ReactNode;
}

/**
 * Per-tab header for the Security pages, ported from SaleOnePos's `SecurityPage`.
 * Each tab supplies its own title + subtitle + leading icon so the header reflects
 * what the tab actually does (Authenticator setup vs. Reset Auth).
 */
export const SecurityHeader: React.FC<SecurityHeaderProps> = ({ title, subtitle, icon }) => (
    <Box sx={{ mb: 2 }}>
        <Stack direction="row" spacing={1.5} sx={{ alignItems: 'center', mb: 0.5 }}>
            {icon ?? <ShieldIcon color="primary" />}
            <Typography variant="h5" sx={{ fontWeight: 700 }}>{title}</Typography>
        </Stack>
        <Typography variant="body2" color="text.secondary">
            {subtitle}
        </Typography>
    </Box>
);
